const llmResponse = $input.first().json;
const batchItems = $('Prepare LLM Prompt').item.json.items;
let text = llmResponse?.text || '';

// Alle JSON-Arrays extrahieren und zusammenführen
const matches = text.match(/\{[^{}]*"index"[^{}]*\}/g);
if (!matches) return [];

const scores = [];
for (const match of matches) {
 try {
 const obj = JSON.parse(match);
 if (obj.index !== undefined && obj.score !== undefined) {
 scores.push(obj);
 }
 } catch(e) {
 continue;
 }
}

const relevantJobs = [];
for (const result of scores) {
 const idx = result.index - 1;
 if (idx >= 0 && idx < batchItems.length && result.score >= 50) {
 relevantJobs.push({
 json: {
 ...batchItems[idx],
 score: result.score,
 reason: result.reason,
 }
 });
 }
}

return relevantJobs;

// Erstellt den finalen HTML-Report
const jobs = $input.first().json.all_relevant_jobs || [];

if (jobs.length === 0) {
 return [{ json: { html: '<p>Keine relevanten Jobs diese Woche gefunden.</p>', subject: 'Job Radar – Keine neuen Treffer' } }];
}

const today = new Date().toLocaleDateString('de-DE', { day:'2-digit', month:'2-digit', year:'numeric' });
const kw = (() => {
 const d = new Date();
 d.setHours(0,0,0,0);
 d.setDate(d.getDate() + 3 - (d.getDay() + 6) % 7);
 const week1 = new Date(d.getFullYear(),0,4);
 return 1 + Math.round(((d-week1)/86400000 - 3 + (week1.getDay()+6)%7)/7);
})();

// ── Sektionen definieren ──────────────────────────────────────────────────────
// Innerhalb jeder Sektion: Watchlist zuerst, dann nach Score absteigend
const sortList = list => list.sort((a, b) => {
 if (b.in_watchlist !== a.in_watchlist) return b.in_watchlist ? 1 : -1;
 return (b.score || 0) - (a.score || 0);
});

const top = sortList(jobs.filter(j => j.score >= 80));
const good = sortList(jobs.filter(j => j.score >= 65 && j.score < 80));
const okay = sortList(jobs.filter(j => j.score >= 55 && j.score < 65));
const nonit = sortList(jobs.filter(j => j.score >= 40 && j.score < 55));

// ── Badge-Helfer ──────────────────────────────────────────────────────────────
const sourceBadge = s => {
 const colors = { indeed: '#b45309', linkedin: '#1d4ed8' };
 return `<span style="background:${colors[s]||'#374151'};color:white;padding:1px 6px;border-radius:6px;font-size:11px;font-weight:500">${s}</span>`;
};

const watchlistBadge = w => w
 ? `<span style="background:#7c3aed;color:white;padding:1px 5px;border-radius:6px;font-size:11px">⭐ Watchlist</span>`
 : '';

const levelBadge = l => {
 if (!l || l === 'Unknown') return '';
 const colors = { Entry: '#0891b2', Mid: '#0284c7', Senior: '#dc2626' };
 return `<span style="background:${colors[l]||'#6b7280'};color:white;padding:1px 5px;border-radius:6px;font-size:11px">${l}</span>`;
};

const scoreBar = s => {
 const color = s >= 80 ? '#16a34a' : s >= 65 ? '#d97706' : s >= 55 ? '#6b7280' : '#9ca3af';
 const width = Math.round(s);
 return `
 <div style="display:flex;align-items:center;gap:6px">
 <div style="flex:1;background:#f3f4f6;border-radius:4px;height:6px;overflow:hidden">
 <div style="width:${width}%;background:${color};height:6px;border-radius:4px"></div>
 </div>
 <span style="font-weight:700;color:${color};font-size:13px;min-width:26px">${s}</span>
 </div>
 <div style="color:#9ca3af;font-size:11px;margin-top:2px">${''}</div>`;
};

// ── Tabellenzeile ─────────────────────────────────────────────────────────────
const row = j => {
 const watchlistRow = j.in_watchlist ? 'background:#faf5ff;' : '';
 const watchlistBorder = j.in_watchlist ? 'border-left:3px solid #7c3aed;' : 'border-left:3px solid transparent;';
 return `
 <tr style="${watchlistRow}${watchlistBorder}border-bottom:1px solid #f3f4f6">
 <td style="padding:10px 8px">
 <a href="${j.url}" style="color:#2563eb;font-weight:600;text-decoration:none;font-size:13px">${j.title}</a>
 <div style="margin-top:3px">${levelBadge(j.level)}</div>
 </td>
 <td style="padding:10px 8px;font-size:13px;color:#374151">
 <div style="font-weight:500">${j.company}</div>
 <div style="margin-top:3px">${watchlistBadge(j.in_watchlist)}</div>
 </td>
 <td style="padding:10px 8px;color:#6b7280;font-size:12px">${j.location}</td>
 <td style="padding:10px 8px">${sourceBadge(j.source)}</td>
 <td style="padding:10px 8px;min-width:120px">
 ${scoreBar(j.score)}
 <div style="color:#9ca3af;font-size:11px;margin-top:2px">${j.reason || ''}</div>
 </td>
 </tr>`;
};

// ── Tabellen-Sektion ──────────────────────────────────────────────────────────
const section = (title, emoji, headerBg, list) => {
 if (list.length === 0) return '';
 const rowsHtml = list.map(row).join('');
 return `
<div style="margin-bottom:28px">
 <h2 style="background:${headerBg};color:white;padding:10px 16px;border-radius:8px 8px 0 0;font-size:14px;margin:0;display:flex;justify-content:space-between;align-items:center">
 <span>${emoji} ${title}</span>
 <span style="opacity:0.75;font-weight:400;font-size:13px">${list.length} Stelle${list.length !== 1 ? 'n' : ''}</span>
 </h2>
 <table style="width:100%;border-collapse:collapse;background:white;border:1px solid #e5e7eb;border-top:none">
 <thead>
 <tr style="background:#f9fafb;border-bottom:1px solid #e5e7eb">
 <th style="padding:8px;text-align:left;font-size:11px;color:#9ca3af;font-weight:600;text-transform:uppercase;width:28%">Titel</th>
 <th style="padding:8px;text-align:left;font-size:11px;color:#9ca3af;font-weight:600;text-transform:uppercase;width:20%">Unternehmen</th>
 <th style="padding:8px;text-align:left;font-size:11px;color:#9ca3af;font-weight:600;text-transform:uppercase;width:17%">Ort</th>
 <th style="padding:8px;text-align:left;font-size:11px;color:#9ca3af;font-weight:600;text-transform:uppercase;width:10%">Quelle</th>
 <th style="padding:8px;text-align:left;font-size:11px;color:#9ca3af;font-weight:600;text-transform:uppercase;width:25%">Score</th>
 </tr>
 </thead>
 <tbody>${rowsHtml}</tbody>
 </table>
</div>`;
};

// ── Statistik-Kacheln ─────────────────────────────────────────────────────────
const statCard = (count, label, color) => `
 <div style="background:white;border-radius:8px;padding:14px 18px;border-left:4px solid ${color};flex:1;min-width:0">
 <div style="font-size:28px;font-weight:700;color:${color}">${count}</div>
 <div style="color:#6b7280;font-size:12px;margin-top:2px">${label}</div>
 </div>`;

const watchlistTotal = jobs.filter(j => j.in_watchlist).length;

// ── HTML zusammenbauen ────────────────────────────────────────────────────────
const html = `<!DOCTYPE html>
<html lang="de">
<head><meta charset="UTF-8"><title>Job Radar KW${kw}</title></head>
<body style="font-family:-apple-system,BlinkMacSystemFont,'Segoe UI',sans-serif;background:#f3f4f6;margin:0;padding:20px">
<div style="max-width:960px;margin:0 auto">

 <!-- Header -->
 <div style="background:linear-gradient(135deg,#1e40af,#7c3aed);color:white;padding:24px 28px;border-radius:12px;margin-bottom:20px">
 <h1 style="margin:0;font-size:22px;font-weight:700">Job Radar – KW${kw}</h1>
 <p style="margin:6px 0 0;opacity:0.8;font-size:14px">${today} · ${jobs.length} relevante Stellen · ${watchlistTotal} Watchlist-Treffer</p>
 </div>

 <!-- Stats -->
 <div style="display:flex;gap:12px;margin-bottom:24px;flex-wrap:wrap">
 ${statCard(top.length, 'Top Match ≥80', '#16a34a')}
 ${statCard(good.length, 'Gut 65–79', '#d97706')}
 ${statCard(okay.length, 'Okay 55–64', '#6b7280')}
 ${statCard(nonit.length, 'Sonstige 40–54', '#d1d5db')}
 ${statCard(watchlistTotal, '⭐ Watchlist-Firmen', '#7c3aed')}
 </div>

 <!-- Sektionen -->
 ${section('Top Matches', '', '#16a34a', top)}
 ${section('Gute Treffer', '', '#d97706', good)}
 ${section('Weitere Treffer','', '#64748b', okay)}
 ${section('Sonstige', '', '#9ca3af', nonit)}

 <div style="text-align:center;color:#9ca3af;font-size:11px;margin-top:24px;padding-bottom:20px">Job Radar · Karlsruhe ≤100km · Automatisch generiert
 </div>

</div>
</body></html>`;

return [{ json: { html, subject: `Job Radar KW${kw} – ${jobs.length} Stellen (${top.length} Top / ${watchlistTotal} Watchlist)` } }];

const response = $input.first().json;
const jobs = response.jobs || [];
return jobs.map(job => ({ json: job }));
